OIDC_PROVIDER_URL = "https://accounts.google.com" # Example for Google
OIDC_CLIENT_ID = os.getenv('OIDC_CLIENT_ID')
OIDC_REDIRECT_URI = "http://localhost:5000/oidc/callback" # Must match a registered redirect URI

if not OIDC_CLIENT_ID:
    raise ValueError("OIDC_CLIENT_ID environment variable not set.")

# --- OIDC Configuration Discovery (simplified for this example) ---
