@app.route('/login')
def login():
    state = generate_state()
    session['oidc_state'] = state

    params = {
        "client_id": OIDC_CLIENT_ID,
        "redirect_uri": OIDC_REDIRECT_URI,
        "scope": "openid profile email", # request profile and email data
        "response_type": "id_token", # Implicit flow
        "state": state,
        # "nonce": "..." # Skip nonce for v1 as per requirements
    }
    auth_url = f"{AUTHORIZATION_ENDPOINT}?{urllib.parse.urlencode(params)}"
    return redirect(auth_url)

@app.route('/oidc/callback')
def oidc_callback():
    # Implicit flow returns parameters in the URL fragment.
    # Flask's request.args parses the query string, not fragment.
    # We expect the frontend JavaScript to send the fragment data to the backend.
    # For a simple Flask app without a frontend, this is a common challenge.
    # A common workaround is to use a simple JS page to extract and POST the fragment.

    # For this example, we'll simulate receiving fragment data directly from a query parameter
    # ONLY FOR DEMONSTRATION. In a real app, this would be a client-side operation.
    # e.g., if the user manually navigates to:
    # http://localhost:5000/oidc/callback?id_token=...&state=...
    # (This is not how OIDC implicit flow works; it uses the URL fragment #)

    # To properly handle the implicit flow, you need a small HTML page that executes JavaScript
    # to read window.location.hash, parse it, and then send it to your backend,
    # either via a form POST or an AJAX call.

    # Example of how you would receive it if the fragment was POSTed/GETted by JS:
    id_token = request.args.get('id_token') or request.form.get('id_token')
    state = request.args.get('state') or request.form.get('state')

    if not id_token or not state:
        flash("Authentication failed: Missing ID Token or State.", 'error')
        app.logger.error("Missing id_token or state in callback.")
        return redirect(url_for('index'))

    # Validate state parameter
    expected_state = session.pop('oidc_state', None)
    if not expected_state or state != expected_state:
        flash("Authentication failed: Invalid state parameter.", 'error')
        app.logger.error(f"State mismatch. Expected: {expected_state}, Received: {state}")
        return redirect(url_for('index'))

    # Decode ID Token
    # IMPORTANT: In a real application, you *MUST* validate the ID Token's signature,
    # expiration, issuer, audience, and nonce (if used).
    # This example only decodes the payload for demonstration.
    userinfo = decode_id_token(id_token)

    if not userinfo:
        flash("Authentication failed: Could not decode ID Token.", 'error')
        app.logger.error("Failed to decode ID Token.")
        return redirect(url_for('index'))

    # Basic ID Token validation (for demonstration, not exhaustive)
    # Check 'exp' (expiration time)
    if 'exp' in userinfo:
        current_time = datetime.utcnow().timestamp()
        if userinfo['exp'] < current_time:
            flash("Authentication failed: ID Token has expired.", 'error')
            app.logger.error(f"ID Token expired at {userinfo['exp']}, current time {current_time}.")
            return redirect(url_for('index'))

    # Check 'iss' (issuer)
    if 'iss' in userinfo and userinfo['iss'] != OIDC_PROVIDER_URL:
        flash("Authentication failed: Invalid ID Token issuer.", 'error')
        app.logger.error(f"Invalid issuer. Expected: {OIDC_PROVIDER_URL}, Got: {userinfo['iss']}")
        return redirect(url_for('index'))

    # Check 'aud' (audience)
    # The 'aud' claim should contain the client ID. It can be a string or an array.
    aud = userinfo.get('aud')
    if isinstance(aud, list):
        if OIDC_CLIENT_ID not in aud:
            flash("Authentication failed: Invalid ID Token audience.", 'error')
            app.logger.error(f"Invalid audience. Expected {OIDC_CLIENT_ID} in {aud}.")
            return redirect(url_for('index'))
    elif aud != OIDC_CLIENT_ID:
        flash("Authentication failed: Invalid ID Token audience.", 'error')
        app.logger.error(f"Invalid audience. Expected {OIDC_CLIENT_ID}, Got {aud}.")
        return redirect(url_for('index'))

    # Store user info in session
    session['userinfo'] = userinfo
    session['id_token'] = id_token # Store for potential future use (e.g., logout with token hint)

    flash("You have been successfully authenticated!", 'success')
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.pop('userinfo', None)
    session.pop('id_token', None)
    session.pop('oidc_state', None)
    flash("You have been logged out.", 'info')
    return redirect(url_for('index'))

